-- 코드를 입력하세요
select distinct crcc.CAR_ID, crcc.CAR_TYPE, (crcc.DAILY_FEE - (crcc.DAILY_FEE * (REPLACE(crcdp.DISCOUNT_RATE, '%') / 100))) * 30 as FEE from CAR_RENTAL_COMPANY_CAR crcc, CAR_RENTAL_COMPANY_RENTAL_HISTORY crcrh, CAR_RENTAL_COMPANY_DISCOUNT_PLAN crcdp where crcc.CAR_ID = crcrh.CAR_ID and crcc.CAR_TYPE = crcdp.CAR_TYPE and (crcc.CAR_TYPE = '세단' or crcc.CAR_TYPE = 'SUV') and crcc.CAR_ID not in (select CAR_ID from CAR_RENTAL_COMPANY_RENTAL_HISTORY where START_DATE <= to_date('2022-11-30', 'yyyy-mm-dd') and END_DATE >= to_date('2022-11-01', 'yyyy-mm-dd')) and crcdp.DURATION_TYPE = '30일 이상' and (crcc.DAILY_FEE - (crcc.DAILY_FEE * (to_number(REPLACE(crcdp.DISCOUNT_RATE, '%')) / 100))) * 30 >= 500000 and (crcc.DAILY_FEE - (crcc.DAILY_FEE * (to_number(REPLACE(crcdp.DISCOUNT_RATE, '%')) / 100))) * 30 < 2000000 order by FEE desc, crcc.CAR_TYPE asc, crcc.CAR_ID desc